    qUid, qTitle, qContent, qRegDate, qPos, qRef, qDepth, qOriUid, qFileName, qFileSize, qStatus, cNum
) values (
    #{qUid}, #{qTitle}, #{qContent}, now(), #{qPos}, #{qRef}, #{qDepth}, #{qOriUid}, #{qFileName}, #{qFileSize}, #{qStatus}, #{cNum}
)

