update qnaBBS
set qTitle = #{qTitle},
    qContent = #{qContent},
    qStatus = #{qStatus}
where qNum = #{qNum}

update qnaBBS
set qPos = qPos + 1
where qRef = #{qRef}
  and qPos > #{qPos}
